// WebGPU compat test #6 — the compute smoke: a WGSL compute shader doubles each
// element of a small storage buffer. createComputePipeline (layout:'auto') →
// createBindGroup off getBindGroupLayout(0) → beginComputePass → setPipeline →
// setBindGroup → dispatchWorkgroups → copyBufferToBuffer staging → mapAsync
// readback. Oracle (Deno) and monster must agree element-for-element.
//
// monster constraints (see README): arrays pass BY VALUE; no DataView/setFloat32
// (bytes via the pure-JS f32bytes IEEE-754 encoder); typed arrays are untyped
// number[]; no array-destructuring in arrow params; JSON keys sort.

function f32bytes(x) {
  if (x === 0) return [0, 0, 0, 0];
  const sign = x < 0 ? 1 : 0;
  x = Math.abs(x);
  let e = Math.floor(Math.log2(x));
  let m = x / Math.pow(2, e);
  if (m < 1) { m *= 2; e -= 1; }
  if (m >= 2) { m /= 2; e += 1; }
  const exp = e + 127;
  const mant = Math.round((m - 1) * Math.pow(2, 23));
  const bits = ((sign << 31) | (exp << 23) | mant) >>> 0;
  return [bits & 0xff, (bits >>> 8) & 0xff, (bits >>> 16) & 0xff, (bits >>> 24) & 0xff];
}
// Decode 4 little-endian bytes back into an f32 (for readback assertions).
function bytesToF32(b0, b1, b2, b3) {
  const bits = ((b0) | (b1 << 8) | (b2 << 16) | (b3 << 24)) >>> 0;
  const sign = (bits >>> 31) & 1 ? -1 : 1;
  const exp = (bits >>> 23) & 0xff;
  const mant = bits & 0x7fffff;
  if (exp === 0) return sign * mant * Math.pow(2, -149);
  if (exp === 255) return mant ? NaN : sign * Infinity;
  return sign * (1 + mant / Math.pow(2, 23)) * Math.pow(2, exp - 127);
}

const out = {};
const adapter = await navigator.gpu.requestAdapter();
const device = await adapter.requestDevice();

const input = [1, 2, 3, 4, 5, 6, 7, 8];
const N = 8;
let inBytes = [];
for (let i = 0; i < N; i++) inBytes = inBytes.concat(f32bytes(input[i]));
// NB (monster two-pass): the runtime evaluates the script speculatively once
// before the real pass, and on that first pass loop-built arrays are empty —
// so `inBytes.length` is 0 there. Buffer SIZES must therefore be derived from
// CONSTANTS (N*4), exactly like the render tests use literal W*4 / bytesPerRow*H.
// (Real aether sizes its buffers from model dims/constants, never from a
// concat-loop length, so this only matters for hand-written smoke tests.)
const byteLen = N * 4; // 32

// Storage buffer: in-place double, readable via COPY_SRC.
const dataBuf = device.createBuffer({
  size: byteLen,
  usage: GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_SRC | GPUBufferUsage.COPY_DST,
});
device.queue.writeBuffer(dataBuf, 0, new Uint8Array(inBytes));

const shader = device.createShaderModule({
  code: `
    @group(0) @binding(0) var<storage, read_write> data: array<f32>;
    @compute @workgroup_size(64)
    fn main(@builtin(global_invocation_id) gid: vec3u) {
      let i = gid.x;
      if (i < ${N}u) { data[i] = data[i] * 2.0; }
    }
  `,
});
const pipeline = device.createComputePipeline({
  layout: 'auto',
  compute: { module: shader, entryPoint: 'main' },
});
const bindGroup = device.createBindGroup({
  layout: pipeline.getBindGroupLayout(0),
  entries: [{ binding: 0, resource: { buffer: dataBuf } }],
});

const enc = device.createCommandEncoder();
const pass = enc.beginComputePass();
pass.setPipeline(pipeline);
pass.setBindGroup(0, bindGroup);
pass.dispatchWorkgroups(1); // 64 threads cover N=8
pass.end();

// Compute outputs can't be MAP_READ directly (STORAGE|MAP_READ is illegal) —
// stage through a copyBufferToBuffer into a COPY_DST|MAP_READ buffer.
const readBuf = device.createBuffer({
  size: byteLen,
  usage: GPUBufferUsage.COPY_DST | GPUBufferUsage.MAP_READ,
});
enc.copyBufferToBuffer(dataBuf, 0, readBuf, 0, byteLen);
device.queue.submit([enc.finish()]);

await readBuf.mapAsync(GPUMapMode.READ);
const px = new Uint8Array(readBuf.getMappedRange());
let result = [];
for (let i = 0; i < N; i++) {
  const o = i * 4;
  result = result.concat([bytesToF32(px[o], px[o + 1], px[o + 2], px[o + 3])]);
}
readBuf.unmap();

out.input = input;
out.output = result; // expected: each input doubled
console.log('__RESULT__ ' + JSON.stringify(out));
